package genxsolution.vms.vmsbackend.employee_hr_management.employee_advance.controller;
import genxsolution.vms.vmsbackend.common.query.ListQueryEngine; import genxsolution.vms.vmsbackend.employee_hr_management.employee_advance.dto.*; import genxsolution.vms.vmsbackend.employee_hr_management.employee_advance.service.EmployeeAdvanceService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/hr/employee-advances") public class EmployeeAdvanceController { private final EmployeeAdvanceService service; public EmployeeAdvanceController(EmployeeAdvanceService service){this.service=service;} @GetMapping public List<EmployeeAdvanceResponse> list(@RequestParam(required=false) UUID companyId,@RequestParam Map<String,String> filters){ return ListQueryEngine.apply(service.list(companyId), filters, Set.of("companyId")); } @GetMapping("/{id}") public EmployeeAdvanceResponse getById(@PathVariable UUID id){ return service.getById(id);} @PostMapping @ResponseStatus(HttpStatus.CREATED) public EmployeeAdvanceResponse create(@RequestBody EmployeeAdvanceUpsertRequest r){ return service.create(r);} @PutMapping("/{id}") public EmployeeAdvanceResponse update(@PathVariable UUID id,@RequestBody EmployeeAdvanceUpsertRequest r){ return service.update(id,r);} @DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable UUID id){ service.delete(id);} }
